-- ============================================================================
-- 141 - AoE Damage backfill from skill text (2026-07-16). The Michelangelo damage-tag
-- gap turned out ROSTER-WIDE, not a collab batch: 390 Rare+ champs have an "Attacks all
-- enemies" skill but no AoE Damage tag (only 193 were tagged) — flagship nukers included.
-- Tags every such champ. status=proposed → human review. Idempotent (NOT EXISTS guard,
-- so the 4 prior rejections — Frozen Banshee et al. — are untouched). Where the same AoE
-- skill also applies Poison/HP Burn, the note carries a REVIEWER flag to verify the hit is
-- real damage beyond the DoT (the Frozen Banshee policy). See damage-tag-underpopulation memo.
-- ============================================================================
insert into champion_tags
  (champion_id, tag_id, status, source_type, source_note, proposed_by, proposed_at, ascension_required, target_type)
select v.champion_id, '8dd046f2-679c-4ff5-9b38-987b7a6af674'::uuid, 'proposed', 'human_observation', v.note,
